class NegativeValueError(ValueError):
    pass

def square_root(n):
    if n < 0:
        raise NegativeValueError("Cannot take square root of negative number")
    return n ** 0.5

try:
    square_root(-4)
except NegativeValueError as e:
    print(e)

class Stack:
    def __init__(self):
        self._items = []

    def push(self, item):
        self._items.append(item)

    def pop(self):
        return self._items.pop()

    def __len__(self):
        return len(self._items)

    def __repr__(self):
        return f"Stack({self._items})"

stack = Stack()
stack.push(1)
stack.push(2)
stack.push(3)
print(len(stack))
print(repr(stack))

